  const tag = document.createElement('style');
  tag.id = 'aws-form-style';
  tag.textContent = `
    .aws-input {
      padding: 9px 12px; border-radius: 8px; border: 1px solid #ccd8e8;
      font-size: 13px; color: #12263a; outline: none; background: #f5f8fc;
      transition: border-color 0.15s; width: 100%; box-sizing: border-box;
    }
    .aws-input:focus { border-color: #1a5fa8; background: #fff; }
    .aws-input-mono { font-family: 'JetBrains Mono', monospace; font-size: 12px; }
  `;
  document.head.appendChild(tag);
}

/* ── FtpCard tách riêng + React.memo → không bị re-render khi parent thay đổi ── */
const FtpCard = React.memo(({ id, index, initial, onRemove, showRemove }) => {
  return (
    <div style={s.ftpCard}>
      <div style={s.ftpTitle}>FTP Server #{index + 1}</div>
      {showRemove && (
        <button type="button" onClick={onRemove} style={s.removeBtn}>Xoá</button>
      )}
      <div style={s.grid2}>
        <div style={s.field}>
          <label style={s.label}>Host</label>
          <input name={`ftp_host_${id}`} className="aws-input"
            defaultValue={initial.ftp_host} />
        </div>
        <div style={s.field}>
          <label style={s.label}>Port</label>
          <input name={`ftp_port_${id}`} className="aws-input" type="number"
            defaultValue={initial.ftp_port} placeholder="21" />
        </div>
        <div style={s.field}>
          <label style={s.label}>Username</label>
          <input name={`ftp_user_${id}`} className="aws-input"
            defaultValue={initial.ftp_user} />
        </div>
        <div style={s.field}>
          <label style={s.label}>Password</label>
          <input name={`ftp_pass_${id}`} className="aws-input" type="password"
            defaultValue={initial.ftp_pass} />
        </div>
        <div style={{ ...s.field, gridColumn: '1 / -1' }}>
          <label style={s.label}>Thư mục</label>
          <input name={`ftp_directory_${id}`} className="aws-input aws-input-mono"
            defaultValue={initial.ftp_directory} placeholder="/data/aws" />
        </div>
      </div>
    </div>
  );
});

/* ── StationForm chính ── */
export default function StationForm({ open, station, onClose, onSave }) {
  // Chỉ state cho những gì ảnh hưởng đến UI layout (danh sách ftp, loading)
  // KHÔNG dùng state cho giá trị input → không bị mất focus
  const [ftpItems, setFtpItems] = useState([{ id: 1, data: { ...EMPTY_FTP } }]);
  const [loading, setLoading] = useState(false);
  const nextId = useRef(2);
  const formRef = useRef();

  useEffect(() => {
    if (!open) return;
    nextId.current = 1;
    const list = station?.ftp_list?.length
      ? station.ftp_list.map(d => ({ id: nextId.current++, data: d }))
      : [{ id: nextId.current++, data: { ...EMPTY_FTP } }];
    setFtpItems(list);
  }, [open, station]);

  if (!open) return null;

  const addFtp = () => {
    setFtpItems(prev => [...prev, { id: nextId.current++, data: { ...EMPTY_FTP } }]);
  };

  const removeFtp = (id) => {
    setFtpItems(prev => prev.filter(f => f.id !== id));
  };

  const handleSubmit = async () => {
    if (!formRef.current) return;
    const fd = new FormData(formRef.current);

    const station_code = fd.get('station_code')?.trim();
    const station_name = fd.get('station_name')?.trim();
    if (!station_code || !station_name) {
      alert('Vui lòng nhập Mã và Tên trạm!');
      return;
    }

    const recharge_date_raw = fd.get('recharge_date');

    // Đọc giá trị FTP theo stable id
    const ftp_list = ftpItems.map(({ id }) => ({
      ftp_host:      fd.get(`ftp_host_${id}`)       || '',
      ftp_port:      Number(fd.get(`ftp_port_${id}`)) || 21,
      ftp_user:      fd.get(`ftp_user_${id}`)       || '',
      ftp_pass:      fd.get(`ftp_pass_${id}`)       || '',
      ftp_directory: fd.get(`ftp_directory_${id}`)  || '',
    }));

    const payload = {
      station_code,
      station_name,
      station_address: fd.get('station_address') || '',
      phone_number:    fd.get('phone_number')    || '',
      recharge_date:   recharge_date_raw ? new Date(recharge_date_raw).toISOString() : null,
      ftp_list,
    };

    setLoading(true);
    await onSave(payload);
    setLoading(false);
  };

  return (
    <div style={s.overlay} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={s.modal}>

        {/* Header */}
        <div style={s.header}>
          <span style={{ fontSize: 17, fontWeight: 700, color: '#0d3b6e' }}>
            {station ? '✏️ Chỉnh sửa trạm' : '➕ Thêm trạm mới'}
          </span>
          <button onClick={onClose}
            style={{ background: 'none', border: 'none', fontSize: 20, cursor: 'pointer', color: '#7a94a8' }}>
            ✕
          </button>
        </div>

        {/* Body — dùng thẻ form để FormData.get() hoạt động */}
        <form ref={formRef} onSubmit={e => e.preventDefault()} style={s.body}>

          {/* Thông tin trạm */}
          <div style={s.section}>
            <div style={s.sectionTitle}>Thông tin trạm</div>
            <div style={s.grid2}>
              <div style={s.field}>
                <label style={s.label}>
                  Mã trạm <span style={{ color: '#b5261e' }}>*</span>
                </label>
                <input name="station_code" className="aws-input"
                  defaultValue={station?.station_code || ''} />
              </div>
              <div style={s.field}>
                <label style={s.label}>
                  Tên trạm <span style={{ color: '#b5261e' }}>*</span>
                </label>
                <input name="station_name" className="aws-input"
                  defaultValue={station?.station_name || ''} />
              </div>
              <div style={s.field}>
                <label style={s.label}>Địa chỉ</label>
                <input name="station_address" className="aws-input"
                  defaultValue={station?.station_address || ''} />
              </div>
              <div style={s.field}>
                <label style={s.label}>Số điện thoại</label>
                <input name="phone_number" className="aws-input"
                  defaultValue={station?.phone_number || ''} />
              </div>
            </div>
            <div style={{ marginTop: 14 }}>
              <div style={s.field}>
                <label style={s.label}>Ngày nạp dữ liệu</label>
                <input name="recharge_date" className="aws-input" type="datetime-local"
                  defaultValue={station?.recharge_date ? station.recharge_date.slice(0, 16) : ''} />
              </div>
            </div>
          </div>

          {/* Danh sách FTP */}
          <div style={s.section}>
            <div style={s.sectionTitle}>Danh sách FTP ({ftpItems.length})</div>
            {ftpItems.map((item, index) => (
              <FtpCard
                key={item.id}         
                id={item.id}
                index={index}
                initial={item.data}
                showRemove={ftpItems.length > 1}
                onRemove={() => removeFtp(item.id)}
              />
            ))}
            <button type="button" onClick={addFtp} style={s.addFtpBtn}>
              + Thêm FTP Server
            </button>
          </div>

        </form>

        {/* Footer */}
        <div style={s.footer}>
          <button onClick={onClose} style={s.btnCancel}>Huỷ</button>
          <button onClick={handleSubmit} disabled={loading}
            style={{ ...s.btnSave, opacity: loading ? 0.7 : 1 }}>
            {loading ? 'Đang lưu...' : station ? 'Cập nhật' : 'Tạo trạm'}
          </button>
        </div>

      </div>
    </div>
  );
}
